import React, { useState, useEffect } from 'react';
import './App.css';
import { QRCodeCanvas as QRCode } from 'qrcode.react';
import { auth, db } from './firebase';
import { 
  signInWithEmailAndPassword, 
  signOut, 
  onAuthStateChanged 
} from 'firebase/auth';
import { 
  doc, 
  getDoc,
  setDoc,
  collection,
  addDoc,
  serverTimestamp 
} from 'firebase/firestore';

function App() {
  const [currentPage, setCurrentPage] = useState('login');
  const [user, setUser] = useState(null);
  const [isManager, setIsManager] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loginError, setLoginError] = useState('');
  const [checkInData, setCheckInData] = useState({
    mood: '',
    energy: '',
    notes: '',
    needSupport: false
  });

  // Check auth state
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      if (user) {
        setUser(user);
        const userDoc = await getDoc(doc(db, 'users', user.uid));
        setIsManager(userDoc.data()?.isManager || false);
        setCurrentPage('home');
      } else {
        setUser(null);
        setIsManager(false);
        setCurrentPage('login');
      }
    });
    return () => unsubscribe();
  }, []);

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      await signInWithEmailAndPassword(auth, email, password);
      setLoginError('');
    } catch (error) {
      setLoginError('Invalid email or password');
    }
  };

  const handleLogout = () => {
    signOut(auth);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!user) return;

    try {
      // Save check-in to Firestore
      const checkInRef = await addDoc(collection(db, 'checkIns'), {
        userId: user.uid,
        userEmail: user.email,
        timestamp: serverTimestamp(),
        ...checkInData
      });

      // If support is needed, notify managers
      if (checkInData.needSupport) {
        await addDoc(collection(db, 'supportRequests'), {
          checkInId: checkInRef.id,
          userId: user.uid,
          userEmail: user.email,
          timestamp: serverTimestamp(),
          status: 'pending'
        });
      }

      alert('Check-in submitted successfully.');
      setCheckInData({
        mood: '',
        energy: '',
        notes: '',
        needSupport: false
      });
    } catch (error) {
      console.error('Error submitting check-in:', error);
      alert('There was an error submitting your check-in. Please try again.');
    }
  };

  // If not logged in, show login page
  if (!user) {
    return (
      <div className="App">
        <div className="login-section">
          <h1>My Tribe Wellbeing Hub</h1>
          <form onSubmit={handleLogin} className="login-form">
            <div className="form-group">
              <label>Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
              />
            </div>
            <div className="form-group">
              <label>Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
              />
            </div>
            {loginError && <p className="error-message">{loginError}</p>}
            <button type="submit">Log In</button>
          </form>
        </div>
      </div>
    );
  }

  const resources = [
    {
      title: "Anna Freud Centre",
      url: "https://www.annafreud.org/",
      description: "Mental health support and resources"
    },
    {
      title: "YoungMinds",
      url: "https://www.youngminds.org.uk/",
      description: "Youth mental health resources"
    },
    {
      title: "Headspace",
      url: "https://www.headspace.com/",
      description: "Mindfulness and meditation (included in vitality healthcare)"
    },
    {
      title: "Training Hub",
      url: "#",
      description: "Access training resources"
    },
    {
      title: "Vitality Benefits",
      url: "https://www.vitality.co.uk/member/",
      description: "Access your wellbeing benefits"
    }
  ];

  const wellbeingActivities = [
    {
      title: "Monthly Theme",
      description: "May 2025: Building Resilience",
      activities: ["Group discussions", "Skill-building workshops", "Reflection exercises"]
    },
    {
      title: "Daily Gratitude Practice",
      description: "Share what you're thankful for",
      frequency: "Daily reflections"
    },
    {
      title: "Mindful Moments",
      description: "Take time to pause and reflect",
      activities: ["Quick breathing exercises", "Guided mindfulness", "Stress relief techniques"]
    }
  ];

  return (
    <div className="App">
      <header className="App-header">
        <div className="header-content">
          <h1>My Tribe Wellbeing Hub</h1>
          <button onClick={handleLogout} className="primary-button">Log Out</button>
        </div>
        <nav className="nav-menu">
          <button 
            className={currentPage === 'home' ? 'active' : ''} 
            onClick={() => setCurrentPage('home')}
          >
            Home
          </button>
          <button 
            className={currentPage === 'checkin' ? 'active' : ''} 
            onClick={() => setCurrentPage('checkin')}
          >
            Daily Check-In
          </button>
          <button 
            className={currentPage === 'resources' ? 'active' : ''} 
            onClick={() => setCurrentPage('resources')}
          >
            Resources
          </button>
          <button 
            className={currentPage === 'wellbeing' ? 'active' : ''} 
            onClick={() => setCurrentPage('wellbeing')}
          >
            Wellbeing Corner
          </button>
          {isManager && (
            <button 
              className={currentPage === 'manager' ? 'active' : ''} 
              onClick={() => setCurrentPage('manager')}
            >
              Manager Dashboard
            </button>
          )}
        </nav>
      </header>

      <main>
        {currentPage === 'home' && (
          <div className="welcome-section">
            <div className="welcome-content">
              <h2>Welcome to Your Wellbeing Space</h2>
              <p className="welcome-message">
                However you're feeling today, you're not alone. This is your space 
                to check in, find support, and connect with your My Tribe community.
              </p>
              
              <div className="quick-access-grid">
                <div className="quick-access-card support">
                  <h3>Need Support?</h3>
                  <div className="support-content">
                    <p className="support-intro">If you need immediate support:</p>
                    <ul className="support-list">
                      <li>
                        <strong>Samaritans</strong><br />
                        Call: 116 123 (free, 24/7)<br />
                        Email: jo@samaritans.org
                      </li>
                      <li>
                        <strong>Crisis Support</strong><br />
                        Text "SHOUT" to 85258<br />
                        Free 24/7 mental health support
                      </li>
                      <li>
                        <strong>Emergency Services</strong><br />
                        Call 999 if you or someone else is in immediate danger
                      </li>
                    </ul>
                  </div>
                  <button onClick={() => setCurrentPage('resources')} className="primary-button">
                    View All Support Options
                  </button>
                </div>

                <div className="quick-access-card daily-wellbeing">
                  <h3>Today's Wellbeing Tip</h3>
                  <div className="tip-content">
                    <p className="tip-header">Take a Mindful Moment</p>
                    <p className="tip-text">
                      Try this quick grounding exercise: Name 5 things you can see, 
                      4 things you can touch, 3 things you can hear, 2 things you 
                      can smell, and 1 thing you can taste.
                    </p>
                  </div>
                  <button onClick={() => setCurrentPage('checkin')} className="primary-button">
                    Check In Now
                  </button>
                </div>

                <div className="quick-access-card upcoming">
                  <h3>Coming Up</h3>
                  <div className="events-list">
                    <div className="event">
                      <span className="event-date">Daily</span>
                      <p className="event-title">Morning Mindfulness</p>
                    </div>
                    <div className="event">
                      <span className="event-date">This Month</span>
                      <p className="event-title">Building Resilience Workshop</p>
                    </div>
                  </div>
                  <button onClick={() => setCurrentPage('wellbeing')} className="primary-button">
                    View All Activities
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}

        {currentPage === 'checkin' && (
          <div className="check-in-form">
            <h2>Daily Check-In</h2>
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label>How are you feeling today?</label>
                <select 
                  value={checkInData.mood}
                  onChange={(e) => setCheckInData({...checkInData, mood: e.target.value})}
                >
                  <option value="">Choose a mood...</option>
                  <option value="great">Great 😊</option>
                  <option value="good">Good 🙂</option>
                  <option value="okay">Okay 😐</option>
                  <option value="low">Low 😔</option>
                </select>
              </div>

              <div className="form-group">
                <label>Energy Level:</label>
                <select 
                  value={checkInData.energy}
                  onChange={(e) => setCheckInData({...checkInData, energy: e.target.value})}
                >
                  <option value="">Select energy level...</option>
                  <option value="high">Fully Charged ⚡</option>
                  <option value="good">Managing Well 👍</option>
                  <option value="low">Running Low 🔋</option>
                  <option value="empty">Need Support 🆘</option>
                </select>
              </div>

              <div className="form-group">
                <label>Would you like support from your manager?</label>
                <div className="checkbox-group">
                  <label>
                    <input
                      type="checkbox"
                      checked={checkInData.needSupport}
                      onChange={(e) => setCheckInData({
                        ...checkInData,
                        needSupport: e.target.checked
                      })}
                    />
                    Yes, I would appreciate support
                  </label>
                </div>
              </div>

              <div className="form-group">
                <label>Any thoughts to share?</label>
                <textarea
                  value={checkInData.notes}
                  onChange={(e) => setCheckInData({...checkInData, notes: e.target.value})}
                  placeholder="Your thoughts are safe here..."
                />
              </div>

              <button type="submit" className="primary-button">Submit Check-in</button>
            </form>
          </div>
        )}

        {currentPage === 'resources' && (
          <div className="resources-section">
            <h2>Support Resources</h2>
            <div className="resources-grid">
              {resources.map((resource, index) => (
                <div key={index} className="resource-card">
                  <h3>{resource.title}</h3>
                  <p>{resource.description}</p>
                  <a href={resource.url} target="_blank" rel="noopener noreferrer">
                    Access Resource
                  </a>
                </div>
              ))}
            </div>
          </div>
        )}

        {currentPage === 'wellbeing' && (
          <div className="wellbeing-corner">
            <h2>Wellbeing Corner</h2>
            <div className="wellbeing-grid">
              {wellbeingActivities.map((activity, index) => (
                <div key={index} className="wellbeing-card">
                  <h3>{activity.title}</h3>
                  <p>{activity.description}</p>
                  {activity.time && <p className="time-info">{activity.time}</p>}
                  {activity.location && <p className="location-info">{activity.location}</p>}
                  {activity.activities && (
                    <ul className="activities-list">
                      {activity.activities.map((item, i) => (
                        <li key={i}>{item}</li>
                      ))}
                    </ul>
                  )}
                  <button className="primary-button">Join Activity</button>
                </div>
              ))}
            </div>
          </div>
        )}

        {currentPage === 'manager' && isManager && (
          <div className="manager-dashboard">
            <h2>Manager Dashboard</h2>
            <div className="support-requests">
              {/* Support requests will be populated here */}
            </div>
          </div>
        )}
      </main>

      <footer className="app-footer">
        <div className="qr-container">
          <p className="qr-text">Scan to access the Wellbeing Hub</p>
          <QRCode 
            value="https://jackfile1.github.io/my-tribe-wellbeing/"
            size={100}
            level="H"
            includeMargin={true}
            className="qr-code"
          />
        </div>
      </footer>
    </div>
  );
}

export default App;


